patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index 04ea12ef0f12..dfecb8325c73 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -968,6 +968,11 @@ bool VectorCombine::scalarizeBinopOrCmp(Instruction &I) {
          (ScalarTy->isIntegerTy() || ScalarTy->isFloatingPointTy() ||
           ScalarTy->isPointerTy()) &&
          "Unexpected types for insert element into binop or cmp");
+  // If the insertion index is out-of-bounds, the insertelement yields poison.
+  // Bail out to avoid illegal extractelement from constant vectors.
+  uint64_t NumElts = cast<VectorType>(VecTy)->getElementCount().getKnownMinValue();
+  if (Index >= NumElts)
+    return false;

   unsigned Opcode = I.getOpcode();
   InstructionCost ScalarOpCost, VectorOpCost;

